# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash
import re

app = Flask(__name__)
app.secret_key = "change-me"

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def is_authenticated():
    return "user_id" in session


def validate_email(email):
    return isinstance(email, str) and bool(EMAIL_RE.match(email.strip()))


def validate_password(password):
    return isinstance(password, str) and len(password) >= 8


def validate_2fa_settings(two_factor):
    if not isinstance(two_factor, dict):
        return False
    if "enabled" in two_factor and not isinstance(two_factor["enabled"], bool):
        return False
    if "method" in two_factor and two_factor["method"] not in {"totp", "sms", "email"}:
        return False
    return True


def update_user_profile(user_id, updates):
    return {
        "user_id": user_id,
        "email": updates.get("email"),
        "password_hash": updates.get("password_hash"),
        "two_factor": updates.get("two_factor"),
    }


@app.route("/api/profile", methods=["PATCH", "POST"])
def update_profile():
    if not is_authenticated():
        return jsonify({"error": "authentication_required"}), 401

    if not request.is_json:
        return jsonify({"error": "json_required"}), 400

    data = request.get_json(silent=True) or {}

    updates = {}

    if "email" in data:
        email = data["email"]
        if not validate_email(email):
            return jsonify({"error": "invalid_email"}), 400
        updates["email"] = email.strip().lower()

    if "password" in data:
        password = data["password"]
        if not validate_password(password):
            return jsonify({"error": "invalid_password"}), 400
        updates["password_hash"] = generate_password_hash(password)

    if "two_factor" in data:
        two_factor = data["two_factor"]
        if not validate_2fa_settings(two_factor):
            return jsonify({"error": "invalid_two_factor_settings"}), 400
        updates["two_factor"] = two_factor

    if not updates:
        return jsonify({"error": "no_valid_updates_provided"}), 400

    user_id = session["user_id"]
    updated_user = update_user_profile(user_id, updates)

    return jsonify({
        "message": "profile_updated",
        "profile": {
            "user_id": updated_user["user_id"],
            "email": updated_user.get("email"),
            "two_factor": updated_user.get("two_factor"),
        }
    }), 200


if __name__ == "__main__":
    app.run(debug=True)